  fprintf(f, "{\n");
  fprintf(f, "  \"scenario\": \"%s\",\n", tb_scenario_str(scn));
  fprintf(f, "  \"profile\": \"%s\",\n", tb_profile_str(prof));
  fprintf(f, "  \"events\": [\n");
  for (size_t i = 0; i < evs->len; i++) {
    const tb_event *ev = &evs->v[i];
