bool tb_q64_push(tb_q64 *q, uint64_t v) {
  if (!q || !q->buf)
    return false;
  if (q->len == q->cap)
    return false;
  q->buf[idx(q, q->len)] = v;
  q->len++;
  return true;
}

bool tb_q64_pop(tb_q64 *q, uint64_t *out) {
  if (!q || !q->buf || !out)
    return false;
  if (q->len == 0)
    return false;
  *out = q->buf[q->head];
  q->head = (q->head + 1) % q->cap;
  q->len--;
